import json
import pathlib

def load_comm(path):
    p = pathlib.Path(path)
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(path, data):
    pathlib.Path(path).write_text(json.dumps(data, ensure_ascii=False, indent=2))

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
"23": {
"1": "<p>Josiah assembles the elders of Judah and Jerusalem for a covenant ceremony at the temple. The formal assembly (<em>wayyiqbōṣ</em>) of elders, priests, prophets, and all the people &#8212; small and great &#8212; reflects the Deuteronomic renewal pattern: the whole covenant community participates in the reading and ratification of the covenant. The formal assembly echoes Joshua&#8217;s Shechem covenant renewal (Josh 24) and foreshadows Ezra&#8217;s public Torah reading (Neh 8:1&#8211;12).</p>",
"2": "<p>Josiah reads aloud in their hearing all the words of the book of the covenant found in the temple. The identification of this book with Deuteronomy &#8212; or a core of it &#8212; has been the dominant hypothesis since de Wette (1805). The public reading of the covenant document fulfills the Deuteronomic prescription for a septennial reading at the Feast of Tabernacles (Deut 31:10&#8211;13) and parallels the inauguration reading by Joshua (Josh 8:34&#8211;35).</p>",
"3": "<p>The king stands by the pillar (<em>ha&#8217;ammûḏ</em>) and makes a covenant before YHWH to follow with all his heart and soul. The pillar designation echoes the royal pillar of Joash&#8217;s coronation (2 Kgs 11:14), marking it as the official royal standing place for covenant ceremonies. The tripartite formula &#8212; all heart, soul, and might &#8212; is Deuteronomic (Deut 6:5) and appears verbatim in the evaluation of Josiah&#8217;s devotion (v25). All the people join the covenant.</p>",
"4": "<p>Josiah commands the high priest Hilkiah to remove all vessels made for Baal, Asherah, and all the host of heaven from the temple. The three-part cult catalogue &#8212; Baal, Asherah, the host of heaven &#8212; represents three distinct streams of apostate worship: Canaanite storm-god cult, Canaanite fertility religion, and the Assyrian-influenced astral religion. The temple had become a multi-cult shrine under Manasseh and Amon; the reform&#8217;s first act is the systematic removal of its entire alien apparatus.</p>",
"5": "<p>Josiah deposes the <em>kᵉmārîm</em> &#8212; the idolatrous priests (<em>qᵉmārîm</em> in Zeph 1:4; Hos 10:5) &#8212; whom the kings of Judah had appointed to make offerings at the high places and to the sun, moon, and constellations. The term <em>kᵉmārîm</em> is an Aramaic loanword (cf. Syriac <em>kāmrāʾ</em>) used exclusively in pejorative contexts for priests of non-YHWH cults. The list of astral objects &#8212; sun, moon, mazālôt (the zodiacal signs or planets) &#8212; reflects the Mesopotamian astral religion that had penetrated Judahite temple practice under Assyrian influence.</p>",
"6": "<p>The Asherah is brought out of the temple, burned at the Kidron Valley, beaten to dust, and scattered on graves. The Kidron Valley served as the primary receptacle for defiling matter from Jerusalem&#8217;s cultic purges (cf. 2 Kgs 15:13; 2 Chr 29:16). The sequence &#8212; removal, burning, grinding, scattering on graves &#8212; represents progressively more thorough defilement: the object is first destroyed then made ritually impure by contact with the dead. Asherah cult objects (wooden poles or stylized trees) are attested at Kuntillet Ajrud and Khirbet el-Qom inscriptions of the 8th century.</p>",
"7": "<p>Josiah tears down the houses of the male cult prostitutes (<em>qᵉḏēšîm</em>) at the temple entrance where women wove garments for the Asherah. The <em>qᵉḏēšîm</em> (literally &#8216;consecrated ones&#8217;) have been variously identified as cultic functionaries in the fertility cult, though modern scholarship debates whether the term always denotes sexual service. The weaving of garments for the Asherah is paralleled in Mesopotamian texts describing the dressing of divine statues; it represents maintenance of the goddess&#8217;s cult image.</p>",
"8": "<p>Josiah brings all the priests from the cities of Judah to Jerusalem and defiles the high places where they had burned offerings, from Geba to Beersheba. The geographical sweep &#8212; Geba (northern border of Judah) to Beersheba (southern border) &#8212; is the standard formula for all of Judah (cf. 1 Sam 3:20 for &#8216;from Dan to Beersheba&#8217;). The centralization of the priesthood at Jerusalem is the implementing act of Deuteronomy&#8217;s prescription that sacrifice be offered only at the chosen place.</p>",
"9": "<p>Despite the removal of high-place priests to Jerusalem, they do not serve at the Jerusalem altar but eat unleavened bread among their brothers. The distinction between high-place priests and temple priests represents a practical compromise between the reform&#8217;s ideological goal (centralized worship) and its economic/social reality (the temple priesthood&#8217;s resistance to admitting country clergy). The category of priests who eat temple support without altar service may correspond to the Deuteronomic Levites dependent on community support (Deut 18:6&#8211;8).</p>",
"10": "<p>Josiah defiles Topheth in the Ben-Hinnom Valley so that no one can sacrifice a son or daughter by fire to Molech. The Topheth &#8212; whose etymology may connect to the Aramaic term for fireplace or the Hebrew <em>tōp</em> (drum, used to drown out cries) &#8212; was the cultic precinct for child sacrifice. Archaeological evidence from Carthage and Phoenician colonies documents <em>molk</em>-sacrifice (burned child offerings) consistent with the biblical Molech cult. Jeremiah attests that this practice continued after Josiah&#8217;s reform (Jer 7:31; 32:35).</p>",
"11": "<p>Josiah removes the horses that the kings of Judah had dedicated to the sun, at the entrance to the temple near the chamber of the officer Nathan-melech, and burns the chariots of the sun with fire. Solar chariot symbolism is well-attested in Mesopotamian and Syro-Palestinian iconography; the winged solar disk was a common royal emblem. The installation of horses &#8212; perhaps statues or live animals &#8212; at the temple entrance represents the incorporation of solar cult iconography into official royal religion, consistent with Assyrian vassal religious practices.</p>",
"12": "<p>Josiah tears down the altars on the roof of the upper chamber of Ahaz and the altars that Manasseh had made in the two courts of the temple. Rooftop altars (cf. Jer 19:13; 32:29; Zeph 1:5) were used for astral worship because the open sky provided unobstructed access to celestial objects. Ahaz had introduced these during the period of Assyrian domination (2 Kgs 16:10&#8211;16); Manasseh expanded them. The destruction of multi-generational installations underscores how deeply the reform had to dig.</p>",
"13": "<p>Josiah defiles the high places east of Jerusalem that Solomon built &#8212; for Ashtoreth of the Sidonians, Chemosh of Moab, and Milcom of the Ammonites. These sites, standing for three centuries since Solomon&#8217;s apostasy (1 Kgs 11:7), are on the Mount of Offense (lit. &#8216;Mount of Destruction,&#8217; a polemical reshaping of &#8216;Mount of Anointing&#8217;). The durability of these cult sites &#8212; surviving from Solomon to Josiah &#8212; illustrates the persistence of royal patronage of foreign cults as diplomatic and personal accommodation.</p>",
"14": "<p>Josiah smashes the sacred pillars (<em>maṣṣēḇôt</em>), cuts down the Asherah poles, and fills the sites with human bones. The use of human bones to defile a cultic site renders it permanently impure under Levitical law (Num 19:16); bones from opened tombs were strategically spread to consecrate the destruction. The <em>maṣṣēḇôt</em> (standing stones) had been prohibited by Deuteronomy (Deut 16:22) but were widely used throughout the ANE as memorial stones, boundary markers, and cult objects.</p>",
"15": "<p>The altar at Bethel &#8212; erected by Jeroboam ben Nebat who made Israel sin &#8212; is torn down, its high place burned, and the Asherah burned. The fall of Bethel&#8217;s altar to a Judahite king is remarkable: Bethel was formally within the former northern kingdom&#8217;s territory, now under Assyrian provincial administration. Josiah&#8217;s ability to act at Bethel reflects either Assyrian weakness during the decline of Ashur-uballit II (612&#8211;609 BCE) or the effective extension of Judahite authority into the Megiddo region during the Assyrian withdrawal.</p>",
"16": "<p>Josiah turns and sees the tombs on the mountain and has the bones taken from them to burn on the altar, defiling it according to the word of YHWH proclaimed by the man of God from Judah (1 Kgs 13:2). The fulfillment notice &#8212; over three centuries after the unnamed prophet&#8217;s oracle at Jeroboam&#8217;s dedication of the Bethel altar &#8212; is one of the most extended prophetic fulfillments in Kings. The precision of the fulfillment &#8212; burning bones on the altar, the man of God from Judah &#8212; validates the deuteronomistic framework of prophecy and fulfillment.</p>",
"17": "<p>Josiah asks what monument he sees; the men of the city explain it is the grave of the man of God who came from Judah and proclaimed these things against the altar. The identification of the grave and its preservation &#8212; by locals who have maintained the tradition for three centuries &#8212; reflects the ANE custom of preserving the tombs of holy men. The narrative detail authenticates the prophetic tradition while setting up the exemption that follows.</p>",
"18": "<p>Josiah orders the bones left undisturbed &#8212; sparing the man of God&#8217;s bones and those of the prophet who came from Samaria. The second prophet buried alongside is the Bethelite prophet of 1 Kgs 13:11&#8211;31 who had deceived the man of God but ultimately acknowledged his authentic prophetic status. The preservation of both men&#8217;s bones is an act of respect for prophetic office, even where the prophets had been in conflict.</p>",
"19": "<p>Josiah removes all the shrines of the high places in the cities of Samaria that the kings of Israel had made. The extension of Josiah&#8217;s reform into the territory of the former northern kingdom reflects the political vacuum created by the Assyrian collapse: Ashurbanipal died around 627 BCE, and the following decades saw rapid Assyrian contraction, allowing Josiah to expand Judahite political and religious influence northward.</p>",
"20": "<p>Josiah kills all the priests of the high places on the altars and burns human bones on them, then returns to Jerusalem. The killing of the northern priests is the most violent act of the reform &#8212; comparable to Elijah&#8217;s massacre of the Baal prophets (1 Kgs 18:40). The reform&#8217;s violence against clergy who were actively maintaining forbidden cult reflects Deuteronomy&#8217;s capital prescription for those who lead Israel into apostasy (Deut 13:5&#8211;9; 17:12).</p>",
"21": "<p>Josiah commands all the people to keep the Passover as written in this book of the covenant. The identification of the discovered document as containing Passover legislation connects it with the Deuteronomic Passover regulations (Deut 16:1&#8211;8), which differ from the Exodus Passover in prescribing celebration at the central sanctuary rather than in individual homes. The Passover as a national pilgrimage festival at Jerusalem marks the climax of centralization.</p>",
"22": "<p>The editorial notice that no such Passover had been kept since the days of the judges &#8212; not during all the days of the kings of Israel or of Judah &#8212; is a deuteronomistic hyperbole asserting the unprecedented scale of Josiah&#8217;s celebration. Hezekiah had also held a major Passover (2 Chr 30:1&#8211;27), but Kings either downplays this or uses a different evaluative criterion. The reference to the judges period suggests the Passover had degenerated from its Mosaic form even before the monarchy.</p>",
"23": "<p>The Passover is held in Jerusalem in the eighteenth year of King Josiah &#8212; 622 BCE by conventional dating. The specific dating &#8212; the same year as the book&#8217;s discovery &#8212; ties the Passover celebration directly to the reform&#8217;s climax. The eighteenth year of Josiah (640&#8211;609 BCE) = 622 BCE, which aligns with the period of Assyrian weakness following Ashurbanipal&#8217;s effective withdrawal from active western campaigning.</p>",
"24": "<p>Josiah eliminates the mediums, spiritists, household gods (<em>tᵉrāpîm</em>), idols (<em>gillûlîm</em>), and all the detestable things seen in Judah and Jerusalem. The <em>tᵉrāpîm</em> (household gods) were small figurines used in domestic cult and divination; Rachel&#8217;s theft of Laban&#8217;s <em>tᵉrāpîm</em> (Gen 31:34) and Michal&#8217;s use of one as a decoy (1 Sam 19:13&#8211;16) show their persistence. The term <em>gillûlîm</em> (&#8216;dung-pellets&#8217;) is Ezekiel&#8217;s characteristic pejorative for idols.</p>",
"25": "<p>The deuteronomistic eulogy of Josiah: no king before him turned to YHWH with all his heart, all his soul, all his might, according to all the Torah of Moses. The triple Deuteronomic formula (<em>bᵉkhol lᵉḇāḇô ûḇᵉkhol napšô ûḇᵉkhol mᵉʾōḏô</em>) from Deut 6:5 is applied as a royal standard for the first and only time to any king in Kings. The superlative evaluation &#8212; none before him &#8212; echoes the structure of other Deuteronomic superlatives (Deut 34:10 for Moses) and sets Josiah as the high point of the monarchy.</p>",
"26": "<p>Nevertheless, YHWH does not turn from his fierce anger against Judah because of all Manasseh&#8217;s provocations. The theological counterweight to Josiah&#8217;s incomparable devotion is the inherited guilt of Manasseh&#8217;s fifty-five-year reign. The Deuteronomistic Historian presents a stark theological paradox: the best reform effort produces no national reprieve because the covenant damage from Manasseh&#8217;s apostasy is irreversible within the monarchical framework.</p>",
"27": "<p>YHWH declares his intention to remove Judah from his presence as he removed Israel, and to reject Jerusalem and the temple. The structural parallel with the northern kingdom&#8217;s fate (2 Kgs 17:18&#8211;20) is complete: what was done to Ephraim will now be done to Judah. The rejection of Jerusalem and the &#8216;chosen&#8217; temple contradicts the conditional promise of 1 Kgs 9:3; the condition of covenant faithfulness was never consistently met.</p>",
"28": "<p>The standard regnal closing formula for Josiah refers the reader to the Book of the Annals of the Kings of Judah. This administrative archive &#8212; distinct from the canonical book of Chronicles &#8212; was presumably maintained by royal scribes and contained records of military campaigns, building projects, and fiscal administration. The formula implies that Josiah&#8217;s full political and military record &#8212; including his northern campaigns &#8212; existed in accessible archives.</p>",
"30": "<p>Josiah&#8217;s servants bring his body from Megiddo to Jerusalem in a chariot and bury him in his own tomb. The ceremonial transfer of the royal body &#8212; <em>wayyarki&#803;ḇûhû mēt mimmegiddô</em> (they carried him dead from Megiddo) &#8212; reflects the ANE protocol for royal burial. The people anoint Jehoahaz as king; the use of anointing (<em>wayyimšᵉḥû</em>) rather than mere accession is unusual and may indicate disputed succession: Jehoahaz was not the eldest son.</p>",
"31": "<p>Jehoahaz is twenty-three years old at accession, reigning only three months (609 BCE). His brief reign is the shortest of any Judahite king. The regnal formula places his mother as Hamutal from Libnah &#8212; a Judahite town &#8212; indicating his maternal lineage differed from his half-brother Eliakim (Jehoiakim), whose mother was from Rumah. The different mothers may reflect different court factions supporting different succession candidates.</p>",
"32": "<p>Jehoahaz does evil in YHWH&#8217;s sight according to all his ancestors did &#8212; the standard negative formula indicating covenant violation, though without specifics. Given the brevity of his reign, the evaluation is likely deuteronomistic shorthand rather than reflecting detailed historical knowledge of his three-month rule. He was presumably not hostile to Josiah&#8217;s reforms given his selection by the people over his older brother.</p>",
"33": "<p>Pharaoh Neco imprisons Jehoahaz at Riblah in the land of Hamath and imposes a tribute of one hundred talents of silver and one talent of gold on Judah. Riblah on the Orontes in central Syria served as the main Egyptian military headquarters in the Levant during 609&#8211;605 BCE &#8212; the same site where Nebuchadnezzar later operated (25:6). The tribute amounts are heavy: one talent of gold = approximately 30 kg; 100 talents of silver = approximately 3,000 kg.</p>",
"34": "<p>Pharaoh Neco makes Eliakim son of Josiah king and changes his name to Jehoiakim; Jehoahaz is taken to Egypt where he dies. The name change from Eliakim (&#8216;God establishes&#8217;) to Jehoiakim (&#8216;YHWH establishes&#8217;) is paradoxical &#8212; Neco, a foreign king, chooses a more explicitly YHWH-centered throne name for his vassal. In the ANE, a suzerain&#8217;s renaming of a vassal king expressed dominion over the vassal&#8217;s identity. Jehoahaz died in Egypt (Jer 22:11&#8211;12).</p>",
"35": "<p>Jehoiakim taxes the land to pay Pharaoh Neco &#8212; exacting silver and gold from the people of the land proportionally. The pro-rated taxation (<em>ʿal pî ʿarāḵô</em>, &#8216;according to his assessment&#8217;) reflects a property-based taxation system. The mechanism &#8212; Jehoiakim collects from landholders and pays Pharaoh &#8212; shows Judah functioning as an Egyptian revenue stream. Jeremiah&#8217;s oracle against Jehoiakim (Jer 22:13&#8211;19) criticizes his use of forced labor for his own building projects during this period.</p>",
"36": "<p>Jehoiakim is twenty-five years old at accession, reigning eleven years in Jerusalem (609&#8211;598 BCE). His mother Zebidah from Rumah has an unusual name &#8212; the name is unique in the OT. Jehoiakim&#8217;s eleven-year reign spans the critical transition from Egyptian to Babylonian hegemony in the Levant, culminating in his rebellion against Nebuchadnezzar that preceded the siege of 597 BCE.</p>",
"37": "<p>Jehoiakim does evil in YHWH&#8217;s sight according to all his ancestors. The evaluation without specification stands in contrast to the extensive prophetic record of Jehoiakim&#8217;s specific crimes in Jeremiah &#8212; burning Jeremiah&#8217;s scroll (Jer 36:23&#8211;25), executing the prophet Uriah (Jer 26:20&#8211;23), building an extravagant palace with forced labor (Jer 22:13&#8211;17). Kings&#8217; silence on these details reflects its genre&#8217;s different focus from the prophetic books.</p>"
},
"24": {
"1": "<p>In Jehoiakim&#8217;s days Nebuchadnezzar of Babylon comes; Jehoiakim serves him three years before rebelling. Nebuchadnezzar&#8217;s decisive victory over Egypt at Carchemish (605 BCE) established Babylonian hegemony over the Levant. The Babylonian Chronicle records Nebuchadnezzar&#8217;s first western campaign immediately after Carchemish. Jehoiakim&#8217;s initial submission (ca. 605 BCE) matches the standard vassal-treaty pattern; his rebellion (ca. 602 BCE) came after Nebuchadnezzar&#8217;s failure against Egypt in 601 BCE.</p>",
"2": "<p>YHWH sends raiding bands of Chaldeans, Arameans, Moabites, and Ammonites against Jehoiakim. The multi-ethnic raiding coalition reflects the imperial strategy of deploying client peoples to punish rebellious vassals before sending the main army. The Babylonian Chronicle confirms Chaldean raids in the western provinces between Nebuchadnezzar&#8217;s withdrawal and his 598/597 BCE siege. The theology &#8212; YHWH sends them &#8212; frames the imperial pressure as covenantal judgment.</p>",
"3": "<p>The editorial aside attributes the raids to the command of YHWH because of the sins of Manasseh and the innocent blood he shed. The theological explanation &#8212; inserted into the narrative of Jehoiakim&#8217;s rebellion &#8212; connects the Babylonian pressure to the deep covenantal debt from Manasseh&#8217;s reign. The &#8216;innocent blood&#8217; (<em>dām nāqî</em>) refers particularly to Manasseh&#8217;s judicial murders (2 Kgs 21:16) and possibly to the execution of prophets.</p>",
"4": "<p>YHWH is not willing to forgive the innocent blood &#8212; he filled Jerusalem with innocent blood. The construction <em>ʾāḇāh lišlōaḥ</em> (literally &#8216;was not pleased to send away&#8217;) emphasizes divine resolution rather than inability. The accumulation of innocent blood as the specific guilt requiring judgment echoes Deuteronomy&#8217;s purgation laws (Deut 19:13; 21:9) which make the land itself guilty if unpunished blood remains. The exile becomes the mechanism by which the land is purged.</p>",
"5": "<p>The regnal closing formula for Jehoiakim directs readers to the Book of the Annals of the Kings of Judah. The compressed treatment of Jehoiakim&#8217;s reign in Kings contrasts with the extensive prophetic material in Jeremiah. Kings focuses on the theological meaning of events; Jeremiah provides the social and religious detail. The combination of the two books gives a fuller picture of the period than either alone.</p>",
"6": "<p>Jehoiakim dies and Jehoiachin his son reigns in his place. The note of Jehoiakim&#8217;s death is unusually terse &#8212; no burial formula, no &#8216;slept with his fathers.&#8217; This is likely deliberate: Jeremiah&#8217;s oracle predicted an &#8216;ass&#8217;s burial&#8217; for Jehoiakim, left unburied outside Jerusalem&#8217;s gates (Jer 22:18&#8211;19; 36:30). The Babylonian Chronicle mentions the siege of Jerusalem in Nebuchadnezzar&#8217;s seventh year (598/7 BCE); Jehoiakim may have died during the siege or just before it.</p>",
"7": "<p>The king of Egypt does not march from his land again because the king of Babylon has taken all that belonged to Egypt from the Brook of Egypt to the Euphrates. The Babylonian Chronicle confirms that after the Battle of Carchemish (605 BCE) and the subsequent campaign of 601 BCE (where Nebuchadnezzar suffered heavy losses but halted Egyptian advance), Egypt&#8217;s Levantine possessions were definitively transferred to Babylonian control. The Euphrates-to-Egypt boundary is the traditional delineation of the Levantine sphere.</p>",
"8": "<p>Jehoiachin is eighteen years old at accession, reigning only three months in Jerusalem (598/597 BCE). The parallel with Jehoahaz&#8217;s three-month reign underscores the dynastic collapse: two successive Davidic kings reigned only three months each before being deposed by foreign powers. The regnal formula dates his accession as the convergence of Nebuchadnezzar&#8217;s siege and Jehoiakim&#8217;s death.</p>",
"9": "<p>Jehoiachin does evil in YHWH&#8217;s sight like everything his father had done. The brief and negative evaluation of Jehoiachin is mitigated by his later rehabilitation in the book&#8217;s final episode (2 Kgs 25:27&#8211;30). The Babylonian administrative tablets (published by E.F. Weidner in 1939) from Nebuchadnezzar&#8217;s palace in Babylon list ration allocations for &#8216;Ia&#8217;ukînu, king of the land of Yahudu&#8217; &#8212; confirming Jehoiachin&#8217;s Babylonian captivity and his continued royal status there.</p>",
"11": "<p>Nebuchadnezzar himself comes to the city while his servants are besieging it. The personal presence of the Babylonian king at the siege &#8212; confirmed in the Babylonian Chronicle: &#8216;in the seventh year, in the month Kislimu, the king of Akkad mustered his army and marched to Hattu-land&#8217; &#8212; marks the campaign&#8217;s importance. The Chronicle records that Nebuchadnezzar &#8216;seized the city of Judah [and] on the second day of the month Addaru he appointed a new king of his own choice&#8217;.</p>",
"12": "<p>Jehoiachin goes out to Nebuchadnezzar along with his mother, servants, princes, and court officials. The voluntary surrender of Jehoiachin &#8212; &#8216;going out&#8217; rather than being captured &#8212; spared Jerusalem the total destruction that would come a decade later under Zedekiah. The surrender preserved the city&#8217;s walls, the majority of the population, and left the temple standing. This is the standard capitulation pattern for a Babylonian siege.</p>",
"13": "<p>Nebuchadnezzar carries off all the treasures of the temple and palace, cutting up all the gold vessels Solomon made for the temple. The cutting (<em>qiṣṣaṣ</em>) of the gold vessels makes them untraceable and easier to transport as bullion. This is the first taking of the temple vessels &#8212; a partial plunder; the more systematic stripping occurs in the 586 BCE destruction (2 Kgs 25:13&#8211;17). The prophetic word in Isa 39:6 (to Hezekiah) had predicted this Babylonian appropriation.</p>",
"14": "<p>Nebuchadnezzar exiles all Jerusalem &#8212; all officials, warriors (10,000 total), and craftsmen and metalworkers &#8212; leaving only the poorest people. The selective deportation strategy targets the leadership and skilled workforce, leaving only those incapable of effective resistance. This Babylonian practice &#8212; confirmed in Assyrian administrative records &#8212; achieves political pacification while retaining the agricultural workforce needed for tax revenue.</p>",
"15": "<p>Nebuchadnezzar carries Jehoiachin to Babylon, along with the king&#8217;s mother (<em>haggᵉḇîrāh</em>), the king&#8217;s wives, his court officials, and the chief men of the land. The prominent mention of the <em>gᵉḇîrāh</em> (queen mother) reflects the institutional importance of the office in the Davidic court. The Babylonian ration tablets confirm that Jehoiachin&#8217;s sons also received rations, suggesting the royal family was kept together.</p>",
"16": "<p>The deportees include 7,000 men of valor, 1,000 craftsmen and metalworkers &#8212; all strong and fit for war. The concentration on the military and artisan classes reflects the same deportation strategy documented in Assyrian records: removing the political, military, and technical capacity that might organize resistance. Jeremiah 29:1&#8211;2 lists the exiled group as elders, priests, prophets, the king and queen mother, court officials, and craftsmen.</p>",
"17": "<p>The king of Babylon makes Mattaniah, Jehoiachin&#8217;s uncle, king in his place and renames him Zedekiah. The renaming &#8212; from Mattaniah (&#8216;gift of YHWH&#8217;) to Zedekiah (&#8216;YHWH is my righteousness&#8217;) &#8212; is again the suzerain&#8217;s act of naming his vassal, claiming sovereignty over his identity. Zedekiah is Josiah&#8217;s third son to reign (after Jehoahaz and Jehoiakim); he is Jehoiachin&#8217;s uncle, not his father.</p>",
"18": "<p>Zedekiah is twenty-one years old at accession, reigning eleven years in Jerusalem (597&#8211;586 BCE). His mother Hamutal from Libnah is the same as Jehoahaz&#8217;s mother (23:31), making Zedekiah and Jehoahaz full brothers and Jehoiakim their half-brother. Zedekiah&#8217;s eleven years &#8212; parallel to Jehoiakim&#8217;s eleven years &#8212; end in the catastrophe of the siege and destruction that Jehoiakim&#8217;s rebellion triggered.</p>",
"19": "<p>Zedekiah does evil in YHWH&#8217;s sight according to all that Jehoiakim had done. The compressed evaluation of Zedekiah in Kings contrasts with the extensive narrative in Jeremiah showing Zedekiah&#8217;s wavering &#8212; personally interested in Jeremiah&#8217;s counsel but ultimately unable to resist his officials&#8217; pressure (Jer 38:14&#8211;26). Kings focuses on the verdict; Jeremiah documents the tragic indecision.</p>",
"20": "<p>It was because of YHWH&#8217;s anger that the things which happened to Jerusalem and Judah happened, until he cast them from his presence &#8212; and Zedekiah rebelled against the king of Babylon. The editorial pivot &#8212; divine anger explaining events, followed immediately by the rebellion that triggers the final destruction &#8212; binds theology and history. Zedekiah&#8217;s rebellion (ca. 589 BCE) likely involved Egyptian encouragement: Pharaoh Hophra (Apries) had promised military support (Jer 37:5).</p>"
},
"25": {
"1": "<p>In Zedekiah&#8217;s ninth year, tenth month, Nebuchadnezzar and his whole army come against Jerusalem and lay siege. The precise dating &#8212; ninth year, tenth month, tenth day &#8212; is preserved also in Jeremiah 52:4 and Ezekiel 24:1&#8211;2 (where Ezekiel dramatically receives the date of the siege in Babylonian captivity). The month Tevet (December/January) was chosen because it allowed siege operations before the spring planting that would supply a besieged city.</p>",
"2": "<p>The city is kept under siege until the eleventh year of King Zedekiah. The eighteen-month siege (January 588 to July 586 BCE) produced catastrophic famine (v3) and is documented in Lamentations&#8217; description of conditions in Jerusalem. Jeremiah&#8217;s purchase of land at Anathoth during the siege (Jer 32:6&#8211;15) was a prophetic act of confidence in post-exilic restoration.</p>",
"3": "<p>By the ninth day of the fourth month the famine is severe and there is no food for the people of the land. The famine&#8217;s severity &#8212; documented in Lamentations 4:4&#8211;10 with images of children begging for bread and nursing mothers boiling their own children &#8212; reflects the standard result of prolonged siege: the besieged population exhausts all food stores. The fourth month, ninth day (= July 586 BCE) is observed as a fast day in the Jewish calendar.</p>",
"4": "<p>A breach is made in the city wall; all the soldiers flee by night through the gate between the two walls by the king&#8217;s garden, while the Chaldeans surround the city. The &#8216;gate between the two walls&#8217; (<em>šaʿar bên hahômōtayim</em>) was presumably a southern gate leading to the Kidron Valley &#8212; the route toward Jericho and the Jordan. The direction of escape &#8212; away from the Babylonian siege lines toward the east &#8212; is consistent with a Babylonian northern and western approach.</p>",
"5": "<p>The Chaldean army pursues Zedekiah and overtakes him in the plains of Jericho; his army scatters from him. The plains of Jericho &#8212; the Jordan Valley &#8212; represent the endpoint of the attempted flight eastward toward the territory beyond the Jordan. Jericho&#8217;s distance from Jerusalem (approximately 23 km east and 1,000 m lower in elevation) shows how far Zedekiah traveled before capture. The scatter of his army reflects the standard disintegration of an army whose command structure has fled.</p>",
"6": "<p>Zedekiah is taken to Riblah in Hamath where Nebuchadnezzar pronounces sentence. Riblah on the Orontes served as the Babylonian military headquarters in Syria &#8212; the same site where Pharaoh Neco had imprisoned Jehoahaz in 609 BCE (23:33). Nebuchadnezzar&#8217;s choice of this location &#8212; halfway between Babylon and Jerusalem &#8212; reflects his use of a Syrian command post to manage western operations without returning to Babylon.</p>",
"7": "<p>The sons of Zedekiah are slaughtered before his eyes; then Zedekiah&#8217;s eyes are put out and he is bound in bronze shackles and carried to Babylon. The sequence &#8212; forced to watch his sons die, then blinded so that is the last sight he has &#8212; is a calculated psychological torture. The blinding of captured kings is documented in Assyrian and Babylonian records as the standard treatment for rebellious vassals; it incapacitates without killing, allowing the captive to serve as a trophy.</p>",
"8": "<p>In the fifth month, seventh day, Nebuzaradan the captain of the guard &#8212; a servant of the king of Babylon &#8212; arrives in Jerusalem. The &#8216;captain of the guard&#8217; (<em>raḇ ṭabbāḥîm</em>, literally &#8216;chief of the slaughterers&#8217; or &#8216;chief of the bodyguard&#8217;) was a senior Babylonian court official. Nebuzaradan appears in Jeremiah 39:9&#8211;10; 40:1&#8211;5 as the official who specifically released Jeremiah from chains. The fifth month, seventh day = approximately August 586 BCE.</p>",
"10": "<p>The Chaldean army tears down the walls of Jerusalem all around. The systematic destruction of city walls &#8212; documented in Lamentations 2:8 (&#8216;he has made rampart and wall to lament; they languish together&#8217;) &#8212; renders the city permanently defenseless. Archaeological excavations at the City of David have uncovered the Babylonian destruction layer: ash, arrowheads, and smashed pottery dated to the 6th century BCE confirming the biblical account.</p>",
"11": "<p>Nebuzaradan deports the rest of the population remaining in the city &#8212; those who had gone over to the king of Babylon and the rest of the multitude. The &#8216;those who had gone over&#8217; refers to deserters who had surrendered during the siege (cf. Jer 38:19); they are deported alongside the remaining loyal population. The comprehensive deportation leaves only the poorest of the poor (v12) for agricultural continuity.</p>",
"12": "<p>The captain of the guard leaves some of the poorest of the land as vinedressers and farmers. The selective retention of agricultural workers is consistent throughout Assyrian and Babylonian deportation practice: the imperial goal is revenue, not depopulation. Vineyards and grain fields require skilled labor; retaining enough workers for basic agricultural production maintained Babylon&#8217;s tax base in the conquered territory.</p>",
"13": "<p>The Chaldeans break up the bronze pillars of the temple, the stands, and the bronze sea, and carry the bronze to Babylon. The bronze pillars &#8212; Jachin and Boaz &#8212; erected by Solomon (1 Kgs 7:15&#8211;22) are among the most prominent temple features. The systematic stripping of temple bronze reflects the standard ancient practice of melting down conquered cult objects for reuse. The 1 Kgs 7 detailed description of these objects acquires retrospective significance as an inventory of what would eventually be lost.</p>",
"14": "<p>All the bronze pots, shovels, snuffers, dishes, and other bronze utensils used in temple service are taken. The comprehensive list of cultic implements mirrors the detailed furnishing inventory of 1 Kgs 7:40&#8211;50. The specific mention of items used in the daily temple service &#8212; ash pans, shovels, snuffers &#8212; emphasizes the total cessation of temple worship that the deportation effected. These were not merely decorative; they were the functional apparatus of the sacrificial system.</p>",
"15": "<p>The gold and silver fire pans and bowls are taken by the captain of the guard. The distinction between items taken by Nebuzaradan (the officer) and items catalogued separately reflects the systematic inventory of temple assets. The fire pans (<em>maḥtôt</em>) and bowls (<em>sippôt</em>) were portable cultic objects; their removal completes the stripping of all temple functionality.</p>",
"16": "<p>The weight of the bronze from the two pillars, the sea, and the stands Solomon had made for the temple is beyond weighing. The formulaic acknowledgment that the bronze is too heavy to weigh underscores the enormous scale of the temple&#8217;s metal wealth. The sea alone &#8212; a cast bronze basin approximately 5 meters in diameter &#8212; would have weighed many tons. Ancient temples functioned partly as state treasuries; the Jerusalem temple&#8217;s wealth reflected centuries of royal deposits.</p>",
"17": "<p>The pillar measurements are reiterated: eighteen cubits high, bronze capital three cubits, network and pomegranates of bronze. The repetition of the pillar dimensions from 1 Kgs 7:15&#8211;22 (with slight variation &#8212; 1 Kgs gives height as 18 cubits; Jer 52:21 gives 18; 2 Chr 3:15 gives 35 cubits for both together) serves as an epitaph for the temple&#8217;s physical magnificence. The detailed measurement of what is destroyed immortalizes what is lost.</p>",
"18": "<p>Nebuzaradan takes Seraiah the chief priest, Zephaniah the second priest, and three doorkeepers in custody. Seraiah is the chief priest at the time of Jerusalem&#8217;s fall &#8212; his lineage traces to Eleazar son of Aaron through Zadok (1 Chr 6:3&#8211;14). Zephaniah the second priest appears in Jeremiah 21:1; 29:25&#8211;29; 37:3 as a moderate official who conveyed messages between Zedekiah and Jeremiah. The doorkeepers &#8212; among the senior Levitical officials &#8212; represent the cultic administrative hierarchy.</p>",
"19": "<p>Nebuzaradan also takes from the city a court official who was the commander of the warriors, five men of the king&#8217;s personal service, the king&#8217;s secretary who enrolled the people of the land, and sixty men of the people of the land. The arrested officials represent the administrative and military structure of the Judahite state: the military commander, royal advisers, the draft administrator, and community leaders. The comprehensive arrest of the bureaucratic class eliminates any organized resistance.</p>",
"20": "<p>Nebuzaradan takes them to the king of Babylon at Riblah. The long journey from Jerusalem to Riblah &#8212; approximately 380 km north through Syria &#8212; was made as prisoners in chains. The appearance before the Babylonian king at his field headquarters follows the protocol for the presentation of captured enemies and their leaders for royal judgment.</p>",
"21": "<p>The king of Babylon strikes and kills them at Riblah in the land of Hamath. The execution of Judah&#8217;s priestly and civil leadership at Riblah marks the definitive end of the Judahite institutional state. The number executed &#8212; seventy men by some counts from vv18&#8211;21 &#8212; represents the core of Jerusalem&#8217;s leadership. Judah is taken into exile from its land, fulfilling the covenantal curse of Deut 28:36, 64.</p>",
"22": "<p>Nebuchadnezzar appoints Gedaliah son of Ahikam son of Shaphan as governor over the people remaining in Judah. Gedaliah&#8217;s appointment reflects Babylonian awareness of an internal Judahite official sympathetic to Babylon. His grandfather Shaphan was the royal secretary who transmitted the Book of the Law to Josiah (22:3&#8211;10); his father Ahikam had protected Jeremiah from execution (Jer 26:24). The Shaphan family were consistently pro-Babylonian and aligned with Jeremiah&#8217;s prophetic counsel.</p>",
"23": "<p>The army commanders &#8212; Ishmael son of Netaniah, Johanan son of Kareah, Seraiah son of Tanhumeth the Netophathite, and Jaazaniah son of the Maacathite &#8212; come with their men to Gedaliah at Mizpah. Mizpah (Tell en-Nasbeh, approximately 12 km north of Jerusalem) served as the administrative center because Jerusalem itself was too destroyed to function. The assembly of military commanders who had evaded capture reflects the remnant of Judahite military leadership still operating in the countryside.</p>",
"24": "<p>Gedaliah swears to them: &#8216;Do not be afraid of the servants of the Chaldeans; settle in the land and serve the king of Babylon and it will go well with you.&#8217; Gedaliah&#8217;s political counsel &#8212; submission to Babylon as the path to survival &#8212; aligns with Jeremiah&#8217;s prophetic position throughout (Jer 27:11&#8211;12; 40:9&#8211;10). The historical realism of his advice is sound: the Babylonian empire was firmly established; resistance could only produce more destruction.</p>",
"25": "<p>In the seventh month Ishmael son of Netaniah son of Elishama of the royal family comes with ten men and strikes down Gedaliah, the Jews and Chaldeans with him at Mizpah. Ishmael&#8217;s royal lineage (&#8216;of royal seed&#8217; &#8212; <em>mizzeraʿ hammelûkhāh</em>) and the patronage of the Ammonite king Baalis (Jer 40:14) suggests the assassination was a royalist reaction to Babylonian-appointed administration. The Jeremiah account (Jer 40:13&#8211;41:18) gives extensive detail about the conspiracy that Kings compresses.</p>",
"26": "<p>All the people, from the least to the greatest, and the army commanders rise and go to Egypt, fearing the Chaldeans. The flight to Egypt &#8212; despite Jeremiah&#8217;s explicit warning not to go (Jer 42:7&#8211;22) &#8212; represents the final dispersal of the Judahite remnant from the land. Egypt&#8217;s established Jewish communities (at Elephantine and elsewhere) may have been reinforced by this migration. The flight south toward Egypt instead of east toward Babylon represents the opposite of the exile&#8217;s geographic resolution.</p>",
"28": "<p>In the thirty-seventh year of the exile of Jehoiachin &#8212; the accession year of Evil-merodach (Amel-Marduk) &#8212; the new Babylonian king lifts up Jehoiachin&#8217;s head and releases him from prison. The precise dating (37th year of exile = 562/1 BCE) coincides with Amel-Marduk&#8217;s first year; the rehabilitation of Jehoiachin is his first recorded political act. The Babylonian administrative tablets confirm Jehoiachin&#8217;s captive status in Babylon and his continuing royal title.</p>",
"29": "<p>Evil-merodach speaks kindly to Jehoiachin and gives him a seat above the seats of the other kings who were with him in Babylon. The elevation above other captive kings reflects the protocol of a Babylonian court where multiple deposed kings were maintained as honorable prisoners. Jehoiachin&#8217;s elevation to the highest rank among them restores his status as the legitimate Davidic king, even in captivity. The Babylonian Chronicle implies that Amel-Marduk may have made broader policy changes at his accession.</p>",
"30": "<p>Jehoiachin receives a regular daily ration (<em>ʾaryēh</em>) from the king for the rest of his life. The provision of a daily royal table-allowance for a captive king is the standard Babylonian mechanism for maintaining a deposed monarch at court. The Babylonian administrative tablets from Nebuchadnezzar&#8217;s reign confirm daily ration allocations for Jehoiachin and his five sons. The book of Kings closes not with a prophetic promise but with this quiet provision &#8212; the Davidic line alive, sustained, awaiting the next chapter of covenant history.</p>"
}
}

def main():
    out_path = "data/commentary/mkt-context/2kings.json"
    existing = load_comm(out_path)
    before = sum(len(existing.get(c, {})) for c in DATA)
    merge_comm(existing, DATA)
    after = sum(len(existing.get(c, {})) for c in DATA)
    save_comm(out_path, existing)
    added = after - before
    print(f"  wrote {out_path}")
    for c in ['23','24','25']:
        print(f"  ch{c}: {len(existing.get(c,{}))} entries")
    print(f"2kings mkt-context ch23-25 fill: added {added} verses")

if __name__ == "__main__":
    main()
